import { useMemo } from "react";
import { useSelect } from "../SelectContext";

/**
 * Shared hook for Dropdown, MultiSelect, ListBox, CascadeSelect.
 * Computes grouped keys and provides common context values.
 */
export const useSelectBase = () => {
    const ctx = useSelect();
    const { childrenKey, labelKey, valueKey } = ctx;

    const isGrouped = !!childrenKey && childrenKey.length > 0;

    const keys = useMemo(
        () => ({
            optionLabel: labelKey,
            optionValue: valueKey,
            optionGroupLabel: isGrouped ? labelKey : undefined,
            optionGroupChildren: isGrouped ? childrenKey : undefined,
        }),
        [labelKey, valueKey, isGrouped, childrenKey],
    );

    return { ...ctx, isGrouped, keys };
};
